// Channels die überwacht werden sollen
// ⚠️ ANPASSEN: Channel-IDs prüfen!
const CHANNELS = [
  { id: 'C0A8WLX7NGY', name: 'abschluesse', label: 'Abschlüsse', priority: 'hoch' },
  { id: 'C0A82BRRS1Y', name: 'kpi-flow', label: 'KPI-Flow', priority: 'hoch' },
  { id: 'C0AEQNWAXC1', name: 'leadqualitaet', label: 'Leadqualität', priority: 'hoch' },
  { id: 'C0A91KKJE9X', name: 'team-setter', label: 'Team Setter', priority: 'mittel' },
  { id: 'C0A7LTX603Z', name: 'team-vetrieb', label: 'Team Vertrieb', priority: 'mittel' },
  { id: 'C0A80AWEEMC', name: 'rechnungsstellung', label: 'Rechnungen', priority: 'mittel' },
  { id: 'C0A7W0GH003', name: 'team-marketing', label: 'Team Marketing', priority: 'mittel' },
];

return CHANNELS.map(c => ({ json: c }));

const channel = $('Channel-Liste').first().json;
const messages = $json.messages || [];

if (messages.length === 0) {
  return [{ json: { skip: true } }];
}

// Nachrichten aufbereiten (ohne Bot-Messages, ohne Joins)
const relevantMsgs = messages
  .filter(m => !m.subtype && !m.bot_id && m.text && m.text.length > 5)
  .map(m => {
    const ts = new Date(parseFloat(m.ts) * 1000);
    const time = ts.getHours() + ':' + String(ts.getMinutes()).padStart(2, '0');
    // Text kürzen auf max 150 Zeichen
    const text = m.text
      .replace(/<@[A-Z0-9]+>/g, '@jemand')
      .replace(/<#[A-Z0-9]+\|([^>]+)>/g, '#$1')
      .replace(/<[^>]+>/g, '')
      .slice(0, 150);
    return { time, text, reactions: (m.reactions || []).length };
  });

const msgCount = relevantMsgs.length;
if (msgCount === 0) {
  return [{ json: { skip: true } }];
}

// Top-Nachrichten: die mit den meisten Reaktionen oder die neuesten
const topMsgs = relevantMsgs
  .sort((a, b) => b.reactions - a.reactions)
  .slice(0, 3)
  .map(m => m.text.slice(0, 100))
  .join(' | ');

const today = new Date().toISOString().slice(0, 10);

const zusammenfassung = `#${channel.name}: ${msgCount} Nachrichten (24h). Highlights: ${topMsgs}`;

return [{
  json: {
    id: 'kf-slack-' + channel.name + '-' + today,
    pid: null,
    quelle: 'slack',
    typ: 'channel-' + channel.name,
    zusammenfassung,
    rohdaten: {
      channel: channel.name,
      messageCount: msgCount,
      topMessages: relevantMsgs.slice(0, 5)
    },
    relevanz: channel.priority,
    created_at: new Date().toISOString(),
    gueltig_bis: today
  }
}];
